import 'dart:convert';

import '../lib/websocket_decoder.dart';
import '../lib/websocket_messages.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

List<int> frame(bool finalFragment, int opcode, String value) {
  final payload = utf8.encode(value);
  if (payload.length > 125) {
    throw ArgumentError('test payload is too large');
  }
  return <int>[(finalFragment ? 0x80 : 0) | opcode, payload.length, ...payload];
}

void main() {
  final wire = <int>[
    ...frame(false, 0x01, 'sensor-'),
    ...frame(true, 0x09, 'p'),
    ...frame(true, 0x00, 'ready'),
    ...frame(true, 0x01, 'next'),
  ];
  final chunks = <List<int>>[
    wire.sublist(0, 1),
    wire.sublist(1, 6),
    wire.sublist(6, 11),
    wire.sublist(11, 12),
    wire.sublist(12, 17),
    wire.sublist(17),
  ];

  final decoder = WebSocketDecoder();
  final assembler = WebSocketMessageAssembler();
  final messages = <String>[];
  for (final chunk in chunks) {
    for (final decoded in decoder.add(chunk)) {
      messages.addAll(assembler.add(decoded));
    }
  }

  check(
    messages.join(',') == 'sensor-ready,next',
    'chunked and coalesced frames preserve message boundaries around control traffic',
  );

  print('final tests passed');
}
